text:
{
  "formal_minutes": {
    "meeting_info": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시각",
        "decision": "스모크 테스트 통과 시 금요일 15:00 KST 공개 릴리스 진행"
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName mismatch 발생 시 먼저 package config를 점검하고, 계약(컨트랙트) 자체가 잘못된 경우에만 스크립트 수정 검토"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스 제안",
        "note": "내부 스트레치 목표이며 확정 일정 아님"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토",
        "state": "목요일까지 가능하면 진행 제안됨, 담당자 미지정"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 릴리스 지연 가능"
      },
      {
        "risk": "README 설치 단계가 최신이 아니면 릴리스 노트가 사용자 오도 가능"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "내부 수요일 스트레치 목표를 릴리스 노트에 명시해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성 tarball 경로 점검",
      "due": "미정",
      "status": "대기(선행결과 필요)",
      "source_certainty": "확정(기한 미설정)"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토",
      "due": "목요일(가능하면)",
      "status": "제안",
      "source_certainty": "부분확정(담당자 미지정)"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 스모크 테스트 결과 통과/실패 여부 확인",
      "실패 시 Doyun의 트리아지 노트(action_items.md) 작성 완료 여부 확인",
      "Minjun 결과 게시 후 Hara의 tarball 경로 점검 결과 확인",
      "README 설치 단계 최신성 검토 담당자 지정 필요 여부 확인",
      "최종 릴리스 승인 권한자 결정 필요",
      "수요일 내부 스트레치 목표의 대외 문서(릴리스 노트) 기재 여부 결정 필요"
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "미지정된 담당자/기한의 임의 확정"
    ]
  },
  "non_invention_rules": {
    "scope_rule": "인라인 공개-안전 합성 픽스처에 명시된 사실만 사용",
    "fact_boundary": [
      "명시되지 않은 고객/예산/보안/장애/법무 사실 추가 금지",
      "미확정 항목(승인권자, 릴리스 노트 기재 여부 등)은 열린 질문으로 유지",
      "내부 스트레치 목표(수요일)와 확정 결정(금요일 15:00 KST)을 혼동하지 않음",
      "거절된 제안은 실행 결정으로 기록하지 않음"
    ]
  }
}
